import { useCallback } from "react";
import Particles from "react-tsparticles";
import { loadSlim } from "tsparticles-slim";

const ColorfulParticleBackground = () => {
    const particlesInit = useCallback(async engine => {
        await loadSlim(engine);
    }, []);

    return (
        <Particles
            id="tsparticles-colorful"
            init={particlesInit}
            options={{
                fullScreen: { enable: false },
                background: {
                    color: {
                        value: "transparent",
                    },
                },
                fpsLimit: 120,
                interactivity: {
                    events: {
                        onClick: {
                            enable: true,
                            mode: "push",
                        },
                        onHover: {
                            enable: true,
                            mode: "repulse",
                        },
                        resize: true,
                    },
                    modes: {
                        push: {
                            quantity: 4,
                        },
                        repulse: {
                            distance: 100,
                            duration: 0.4,
                        },
                    },
                },
                particles: {
                    color: {
                        value: ["#ff0000", "#00ff00", "#0000ff", "#ffff00", "#ff00ff", "#00ffff"], // Multiple vivid colors
                    },
                    links: {
                        color: "#ffffff",
                        distance: 150,
                        enable: true,
                        opacity: 0.3,
                        width: 1,
                    },
                    move: {
                        direction: "none",
                        enable: true,
                        outModes: {
                            default: "bounce",
                        },
                        random: false,
                        speed: 2,
                        straight: false,
                    },
                    number: {
                        density: {
                            enable: true,
                            area: 800,
                        },
                        value: 50,
                    },
                    opacity: {
                        value: 0.5,
                    },
                    shape: {
                        type: "circle",
                    },
                    size: {
                        value: { min: 1, max: 3 },
                    },
                },
                detectRetina: true,
            }}
            className="absolute inset-0 z-0 h-full w-full"
        />
    );
};

export default ColorfulParticleBackground;

import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, Ticket, Video, Image as ImageIcon, User, Languages, Search, MoreHorizontal, Sun, Moon } from 'lucide-react';
import clsx from 'clsx';
import { motion, AnimatePresence } from 'framer-motion';
import templeImg from '../assets/temple/amman_temple.jpeg';
import { useTheme } from '../context/ThemeContext';

const PRIMARY_ITEMS = [
    { key: 'home', label: { en: 'Home', ta: 'முகப்பு' }, path: '/' },
    { key: 'book', label: { en: 'Book Token', ta: 'முன்பதிவு' }, path: '/book', icon: Ticket },
    { key: 'tracking', label: { en: 'Status', ta: 'நிலை' }, path: '/tracking', icon: Search },
    { key: 'live', label: { en: 'Live Updates', ta: 'நேரலை' }, path: '/live', icon: Video },
];

const SECONDARY_ITEMS = [
    { key: 'gallery', label: { en: 'Bull Gallery', ta: 'காளைகள்' }, path: '/gallery', icon: ImageIcon },
    { key: 'videos', label: { en: 'Videos', ta: 'காணொளிகள்' }, path: '/#videos', icon: Video },
    { key: 'admin', label: { en: 'Admin', ta: 'நிர்வாகம்' }, path: '/admin', icon: User },
];

const ALL_ITEMS = [...PRIMARY_ITEMS, ...SECONDARY_ITEMS];

export default function Navbar({ lang, setLang }) {
    const [isOpen, setIsOpen] = useState(false);
    const { theme, toggleTheme } = useTheme();
    const location = useLocation();

    return (
        <nav className="fixed top-0 w-full z-[100] bg-white/80 dark:bg-black/80 backdrop-blur-md border-b border-black/10 dark:border-white/10 transition-colors duration-300">
            <div className="w-full mx-auto px-4 lg:px-8">
                <div className="flex items-center justify-between h-20">

                    {/* Logo */}
                    <Link to="/" className="flex items-center gap-3 group shrink-0">
                        <div className="w-10 h-10 rounded-full bg-gradient-to-br from-thiru-gold to-thiru-red p-0.5 overflow-hidden group-hover:scale-110 transition-transform">
                            <img src={templeImg} alt="Logo" className="w-full h-full object-cover rounded-full" />
                        </div>
                        {lang === 'ta' ? (
                            <span className="hidden lg:block text-sm font-bold text-thiru-gold font-tamil whitespace-nowrap">
                                திருநல்லூர் ஜல்லிக்கட்டு
                            </span>
                        ) : (
                            <div className="hidden lg:flex flex-col">
                                <span className="text-xl font-bold text-thiru-gold leading-none">
                                    THIRUNALLUR
                                </span>
                                <span className="text-xs text-red-500 font-semibold tracking-wider">
                                    JALLIKATTU
                                </span>
                            </div>
                        )}
                    </Link>

                    {/* Desktop Nav */}
                    <div className="hidden md:flex items-center gap-1 xl:gap-2">
                        {ALL_ITEMS.map((item) => {
                            const Icon = item.icon;
                            const isActive = location.pathname === item.path;
                            return (
                                <Link
                                    key={item.key}
                                    to={item.path}
                                    className={clsx(
                                        "flex items-center gap-1.5 px-2 py-1 rounded-md transition-all text-[10px] lg:text-xs font-bold uppercase tracking-wide border whitespace-nowrap",
                                        isActive
                                            ? "bg-blue-900 text-white border-blue-400 shadow-[0_0_15px_rgba(59,130,246,0.5)]"
                                            : "bg-gray-100 dark:bg-black text-blue-600 dark:text-blue-500 border-gray-200 dark:border-blue-800 hover:bg-blue-100 dark:hover:bg-blue-800 hover:text-blue-800 dark:hover:text-white hover:border-blue-300 dark:hover:border-blue-400 shadow-none dark:shadow-[0_0_10px_rgba(30,58,138,0.3)]",
                                        lang === 'ta' && "font-tamil"
                                    )}
                                >
                                    {Icon && <Icon size={12} className="lg:w-3.5 lg:h-3.5" />}
                                    {item.label[lang]}
                                </Link>
                            );
                        })}

                        <button
                            onClick={() => setLang(l => l === 'en' ? 'ta' : 'en')}
                            className="flex items-center gap-2 px-3 py-1 bg-red-900/20 border border-red-900/50 rounded-full text-red-400 hover:text-red-300 text-xs font-bold transition-colors ml-2"
                        >
                            <Languages size={14} />
                            {lang === 'en' ? 'தமிழ்' : 'ENG'}
                        </button>

                        <button
                            onClick={toggleTheme}
                            className="p-1.5 ml-1 rounded-full bg-gray-100 dark:bg-white/10 text-yellow-600 dark:text-yellow-400 hover:bg-gray-200 dark:hover:bg-white/20 transition-colors"
                            aria-label="Toggle Theme"
                        >
                            {theme === 'dark' ? <Sun size={14} /> : <Moon size={14} />}
                        </button>
                    </div>

                    {/* Mobile Menu Button */}
                    <div className="md:hidden flex items-center gap-4">
                        <button
                            onClick={() => setLang(l => l === 'en' ? 'ta' : 'en')}
                            className="text-thiru-gold font-bold text-sm"
                        >
                            {lang === 'en' ? 'TA' : 'EN'}
                        </button>
                        <button onClick={() => setIsOpen(!isOpen)} className="text-zinc-400 hover:text-white">
                            {isOpen ? <X size={28} /> : <Menu size={28} />}
                        </button>
                    </div>
                </div>
            </div>

            {/* Mobile Menu */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        className="md:hidden bg-zinc-950 border-b border-white/10 overflow-hidden"
                    >
                        <div className="px-4 pt-2 pb-6 space-y-2">
                            {ALL_ITEMS.map((item) => (
                                <Link
                                    key={item.key}
                                    to={item.path}
                                    onClick={() => setIsOpen(false)}
                                    className={clsx(
                                        "block px-3 py-3 rounded-md text-base font-medium border-b border-white/5",
                                        location.pathname === item.path ? "text-thiru-gold" : "text-zinc-400",
                                        lang === 'ta' && "font-tamil"
                                    )}
                                >
                                    {item.label[lang]}
                                </Link>
                            ))}
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </nav>
    );
}

import { useCallback, useMemo } from "react";
import Particles from "react-tsparticles";
import { loadSlim } from "tsparticles-slim";
import { useLocation } from "react-router-dom";

const ParticleBackground = () => {
    const particlesInit = useCallback(async (engine) => {
        await loadSlim(engine);
    }, []);

    const location = useLocation();

    const options = useMemo(() => {
        const path = location.pathname;

        // Configuration for text-heavy or form pages (Registration, Admin, Tracking, Live)
        const isMinimalPage = ['/book', '/tracking', '/admin', '/live'].includes(path);

        // Configuration for media-heavy pages (Gallery, Videos)
        const isMediaPage = ['/gallery', '/videos'].includes(path);

        if (isMinimalPage) {
            return {
                fullScreen: { enable: false },
                background: { color: { value: "transparent" } },
                fpsLimit: 120,
                interactivity: {
                    events: {
                        onClick: { enable: true, mode: "push" },
                        onHover: { enable: true, mode: "repulse" },
                        resize: true,
                    },
                    modes: {
                        push: { quantity: 2 },
                        repulse: { distance: 100, duration: 0.4 },
                    },
                },
                particles: {
                    color: { value: ["#7F1D1D", "#A16207"] }, // Darker Red (900) & Darker Gold (700)
                    links: { enable: false }, // No connecting lines for cleaner look
                    move: {
                        direction: "none",
                        enable: true,
                        outModes: { default: "bounce" },
                        random: true,
                        speed: 0.5, // Slower movement
                        straight: false,
                    },
                    number: {
                        density: { enable: true, area: 800 },
                        value: 30, // Fewer particles
                    },
                    opacity: { value: 0.6 }, // Increased opacity for visibility of dark colors
                    shape: { type: "circle" },
                    size: { value: { min: 1, max: 3 } },
                },
                detectRetina: true,
            };
        }

        if (isMediaPage) {
            return {
                fullScreen: { enable: false },
                background: { color: { value: "transparent" } },
                fpsLimit: 120,
                interactivity: {
                    events: {
                        onClick: { enable: true, mode: "push" },
                        resize: true,
                    },
                    modes: {
                        push: { quantity: 4 },
                    },
                },
                particles: {
                    color: { value: "#A16207" }, // Dark Gold (700)
                    links: {
                        color: "#A16207",
                        distance: 150,
                        enable: true,
                        opacity: 0.3, // Slightly more visible
                        width: 2, // Enlarged width
                    },
                    move: {
                        direction: "none",
                        enable: true,
                        outModes: { default: "bounce" },
                        random: false,
                        speed: 1,
                        straight: false,
                    },
                    number: {
                        density: { enable: true, area: 800 },
                        value: 50,
                    },
                    opacity: { value: 0.5 },
                    shape: { type: "circle" },
                    size: { value: { min: 1, max: 4 } },
                },
                detectRetina: true,
            };
        }

        // Default Configuration (Home, Menu) - High Energy
        return {
            fullScreen: { enable: false },
            background: {
                color: { value: "transparent" },
            },
            fpsLimit: 120,
            interactivity: {
                events: {
                    onClick: { enable: true, mode: "push" },
                    onHover: { enable: true, mode: "grab" },
                    resize: true,
                },
                modes: {
                    push: { quantity: 4 },
                    grab: { distance: 140, links: { opacity: 1 } }
                },
            },
            particles: {
                color: {
                    value: ["#991B1B", "#7F1D1D", "#CA8A04", "#A16207", "#EAB308"], // Rich Theme Palette
                    animation: {
                        enable: true,
                        speed: 20,
                        sync: true
                    }
                },
                links: {
                    color: "#A16207", // Dark Gold (700) - Darker
                    distance: 150,
                    enable: true,
                    opacity: 0.5, // More visible
                    width: 2, // Enlarged width
                },
                move: {
                    direction: "none",
                    enable: true,
                    outModes: { default: "bounce" },
                    random: false,
                    speed: 2,
                    straight: false,
                },
                number: {
                    density: { enable: true, area: 800 },
                    value: 100,
                },
                opacity: { value: 0.8 },
                shape: { type: "circle" },
                size: { value: { min: 2, max: 6 } },
            },
            detectRetina: true,
        };
    }, [location.pathname]);

    return (
        <div className="fixed inset-0 -z-0 pointer-events-none">
            <Particles
                id="tsparticles"
                init={particlesInit}
                className="w-full h-full"
                options={options}
            />
        </div>
    );
};

export default ParticleBackground;

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Video, Play, ExternalLink, X } from 'lucide-react';
import clsx from 'clsx';

